document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".checkbox-include-unknown").forEach(e=>{const r=e.closest(".row.g-3");if(!r)return;const n=r.querySelector(".numeric-slider-range");if(!n)return;const t=document.getElementById(`${n.id}_is_null`);t&&(t.value=n.dataset.cur_is_null,e.checked=t.value==="true")}),document.querySelectorAll(".checkbox-include-unknown").forEach(e=>{e.addEventListener("click",()=>{const r=e.closest(".row.g-3");if(!r)return;const n=r.querySelector(".numeric-slider-range");if(!n)return;const t=document.getElementById(`${n.id}_is_null`);t&&(t.value=e.checked.toString())})})});
